import './App.css';
import React from 'react';
import Topbar from './Topbar';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Home from './pages/Home';
// import Services from './Services';
// import Products from './Products';
import Contact from './Contact';
import Content from './Content';
import ArticleSono from './ArticleSono';
import ArticleYoga from './ArticleSono';
import Yoga from './Yoga';
import Voyage from './Voyage';
import Coaching from './Coaching';
import Events from './Events';
import Footer from './Footer';



function App() {

  return (
    <div className="App">
      <Router >

        <Switch>
          <Route path="/" exact component={Home} >
          <Home />
          </Route>
            <Route path="/contact" exact component={Contact} >
            <Contact />
          </Route>
            <Route path="/yoga" exact component={Yoga} >
            <Yoga />
            </Route>
            <Route path="/voyage" exact component={Voyage} >
              <Voyage />
            </Route>
            <Route path="/coaching" exact component={Coaching} >
            <Coaching />
          </Route>
          <Route path="/events" exact component={Events} >
            <Events />
          </Route>
          <Route path="/content" exact component={Content} >
            <Content />
          </Route>
          <Route path="/articleSono" exact component={ArticleSono} >
            <ArticleSono />
          </Route>
          <Route path="/articleYoga" exact component={ArticleYoga} >
            <ArticleYoga />
          </Route>
        </Switch>
        <Footer />
      </Router>
    </div>
  );
}

export default App;
